    "id": "pdf-n5-024",
    "title": "する",
    "level": "N5",
    "bookOrder": 24,
    "meaning": "做……；佩戴（小物品）；构成サ变动词",
    "structure": "名詞＋を＋する／名詞＋する",
    "connection": "名詞＋を＋する／名詞＋する",
